40 | /**
41 |  * Eclipseの.classpathに記載されたJARファイルのSHA1ハッシュを計算し、
42 |  * Maven Central REST APIで依存関係情報を検索するクラス。
43 |  */
44 | public class DependencyResolver {
45 | 
46 |     private static final Logger log = AppLogger.get(DependencyResolver.class);
47 | 
48 |     private static final String MAVEN_SEARCH_URL =
49 |             "https://search.maven.org/solrsearch/select?q=1:%s&rows=1&wt=json";
50 | 
51 | 
52 |     private final HttpClient httpClient;
53 | 
54 |     public DependencyResolver() {
55 |         this.httpClient = HttpClient.newBuilder()
56 |                 .connectTimeout(Duration.ofSeconds(10))
57 |                 .sslContext(createTrustAllSslContext())
58 |                 .build();
59 |     }
60 | 
61 |     /**
62 |      * SSLインスペクション環境向けに、証明書検証を行わないSSLContextを生成する。
63 |      */
64 |     private static SSLContext createTrustAllSslContext() {
65 |         TrustManager[] trustAll = new TrustManager[]{
66 |             new X509TrustManager() {
67 |                 @Override public void checkClientTrusted(X509Certificate[] chain, String authType) {}
68 |                 @Override public void checkServerTrusted(X509Certificate[] chain, String authType) {}
69 |                 @Override public X509Certificate[] getAcceptedIssuers() { return new X509Certificate[0]; }
70 |             }
71 |         };
72 |         try {
73 |             SSLContext ctx = SSLContext.getInstance("TLS");
74 |             ctx.init(null, trustAll, new java.security.SecureRandom());
75 |             return ctx;
76 |         } catch (NoSuchAlgorithmException | KeyManagementException e) {
77 |             throw new IllegalStateException("SSL証明書検証バイパス用SSLContextの生成に失敗しました", e);
78 |         }
79 |     }
80 | 
81 |     /**
82 |      * {@link JarFile} のリストを受け取り、Maven依存関係リストに解決して返す。
83 |      *
84 |      * @param jarFiles Eclipseの.classpathから構築した {@link JarFile} のリスト
85 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ（相対パス解決の基準）
86 |      * @return 解決済みの {@link MavenDependency} リスト
87 |      */
88 |     public static List<MavenDependency> resolve(List<JarFile> jarFiles, Path inputDir) {
89 |         DependencyResolver resolver = new DependencyResolver();
90 |         List<MavenDependency> results = new ArrayList<>();
91 |         for (JarFile jarFile : jarFiles) {
92 |             results.add(resolver.resolveJar(jarFile, inputDir));
93 |         }
94 |         return results;
95 |     }
96 | 
97 |     /**
98 |      * 1つの {@link JarFile} を解決する。
99 |      *
100 |      * <p>スコープは {@link JarFile} の {@code test} / {@code exported} 属性から決定する：</p>
101 |      * <ul>
102 |      *   <li>{@code test=true} → Maven {@code test} スコープ</li>
103 |      *   <li>{@code exported=true} → Maven compile スコープ（scope要素なし）</li>
104 |      *   <li>それ以外 → Maven {@code provided} スコープ</li>
105 |      * </ul>
106 |      *
107 |      * @param jarFile  解決対象の {@link JarFile}
108 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ
109 |      * @return 解決済みの {@link MavenDependency}
110 |      */
111 |     private MavenDependency resolveJar(JarFile jarFile, Path inputDir) {
112 |         String jarPath = jarFile.path();
113 |         // JarFile の属性からスコープを決定する
114 |         final String scope;
115 |         if (jarFile.test()) {
116 |             scope = "test";
117 |         } else if (jarFile.exported()) {
118 |             scope = null; // compile (Maven デフォルト)
119 |         } else {
120 |             scope = "provided";
121 |         }
122 |         Path path = Path.of(jarPath).isAbsolute()
123 |                 ? Path.of(jarPath)
124 |                 : inputDir.resolve(jarPath);
125 | 
126 |         String jarFileName = path.getFileName().toString();
127 |         // 拡張子なしのベース名
128 |         String baseName = jarFileName.endsWith(".jar")
129 |                 ? jarFileName.substring(0, jarFileName.length() - 4)
130 |                 : jarFileName;
131 | 
132 |         log.info("  Resolving: {} ...", jarFileName);
133 | 
134 |         if (!Files.exists(path)) {
135 |             log.warn("  [WARN] JARファイルが見つかりません: {} → systemスコープとして扱います", path);
136 |             log.info("  → not found (system scope): {}", jarFileName);
137 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", jarPath);
138 |         }
139 | 
140 |         String sha1;
141 |         try {
142 |             sha1 = FileUtils.computeSha1(path);
143 |         } catch (Exception e) {
144 |             log.error("  [ERROR] SHA1計算に失敗しました: {} → {}", path, e.getMessage());
145 |             log.info("  → SHA1 error (system scope): {}", jarFileName);
146 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
147 |         }
148 | 
149 |         try {
150 |             String json = callMavenCentralApi(sha1);
151 |             return parseResponse(json, baseName, path.toAbsolutePath().toString(), scope);
152 |         } catch (Exception e) {
153 |             log.error("  [ERROR] Maven Central API呼び出しに失敗しました: {} → {}", jarFileName, e.getMessage());
154 |             log.info("  → API error (system scope): {}", jarFileName);
155 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
156 |         }
157 |     }
158 | 
159 |     /**
160 |      * Maven Central Search APIを呼び出してJSONレスポンスを返す。
161 |      * テスト用にprotectedとして定義し、サブクラスでオーバーライド可能にする。
162 |      */
163 |     protected String callMavenCentralApi(String sha1) throws IOException, InterruptedException {
164 |         String url = String.format(MAVEN_SEARCH_URL, sha1);
165 |         HttpRequest request = HttpRequest.newBuilder()
166 |                 .uri(URI.create(url))
167 |                 .timeout(Duration.ofSeconds(10))
168 |                 .GET()
169 |                 .build();
170 |         HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
171 |         return response.body();
172 |     }
173 | 
174 |     // private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\"\\s*:\\s*\"([^\"]+)\"");
175 |     // private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\"\\s*:\\s*\"([^\"]+)\"");
176 |     // private static final Pattern VERSION_PATTERN     = Pattern.compile("\"latestVersion\"\\s*:\\s*\"([^\"]+)\"");
177 |     // private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
178 |     private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\":\"([^\"]+)\"");
179 |     private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\":\"([^\"]+)\"");
180 |     private static final Pattern VERSION_PATTERN     = Pattern.compile("\"v\":\"([^\"]+)\"");
181 |     private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
182 | 
183 |     /**
184 |      * Maven Central APIのJSONレスポンスをパースしてMavenDependencyを返す。
185 |      *
186 |      * <p>Maven Central で見つかった場合のスコープは {@code scope} をそのまま使う。</p>
187 |      */
188 |     private static MavenDependency parseResponse(String json, String baseName,
189 |                                                  String absolutePath, String scope) {
190 |         // numFound:0 なら見つからなかった
191 |         Matcher numFoundMatcher = NUM_FOUND_PATTERN.matcher(json);
192 |         if (numFoundMatcher.find()) {
193 |             int numFound = Integer.parseInt(numFoundMatcher.group(1));
194 |             if (numFound == 0) {
195 |                 log.info("  → not found in Maven Central (system scope): {}", baseName);
196 |                 return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
197 |             }
198 |         }
199 | 
200 |         Matcher gMatcher = GROUP_ID_PATTERN.matcher(json);
201 |         Matcher aMatcher = ARTIFACT_ID_PATTERN.matcher(json);
202 |         Matcher vMatcher = VERSION_PATTERN.matcher(json);
203 | 
204 |         if (gMatcher.find() && aMatcher.find() && vMatcher.find()) {
205 |             String groupId    = gMatcher.group(1);
206 |             String artifactId = aMatcher.group(1);
207 |             String version    = vMatcher.group(1);
208 |             log.info("  → found: {}:{}:{}", groupId, artifactId, version);
209 |             return new MavenDependency(groupId, artifactId, version, scope, null);
210 |         }
211 | 
212 |         // パースに失敗した場合もsystemスコープ
213 |         log.warn("  [WARN] Maven Central APIレスポンスのパースに失敗しました: {}", baseName);
214 |         log.info("  → parse error (system scope): {}", baseName);
215 |         return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
216 |     }
217 | }
