31 | /**
32 |  * EclipseプロジェクトのソースファイルをMavenの標準ディレクトリ構造にコピーするクラス。
33 |  *
34 |  * <ul>
35 |  *   <li>Javaソース (.java) → src/main/java/ または src/test/java/</li>
36 |  *   <li>リソースファイル (非.java) → src/main/resources/ または src/test/resources/</li>
37 |  *   <li>Webコンテンツ (WTPプロジェクトの場合) → src/main/webapp/</li>
38 |  * </ul>
39 |  *
40 |  * <p>{@code convertToUtf8} が {@code true} の場合、以下の変換を行う：</p>
41 |  * <ul>
42 |  *   <li>{@code .java} ファイル: {@code sourceEncoding} で読み込み、UTF-8 で書き出す</li>
43 |  *   <li>{@code .properties} ファイル: {@code sourceEncoding} で読み込み、Unicode エスケープを
44 |  *       Unicode 文字に展開して UTF-8 で書き出す。{@code effectiveTargetVersion <= 8} の場合は
45 |  *       {@code src/main/resources-utf8/} へ出力する</li>
46 |  *   <li>{@code .jsp} ファイル: {@code pageEncoding} 属性を検出してそのエンコードで読み込み、
47 |  *       属性値を {@code UTF-8} に書き換えて出力する</li>
48 |  * </ul>
49 |  */
50 | public class ProjectCopier {
51 | 
52 |     private static final Logger log = AppLogger.get(ProjectCopier.class);
53 | 
54 |     private ProjectCopier() {}
55 | 
56 |     /** ISO-8859-1 でプリアンブルを読む際のバッファサイズ（4KB）。 */
57 |     private static final int JSP_PREAMBLE_BYTES = 4096;
58 | 
59 |     /** JSP の pageEncoding 属性を検出する正規表現。 */
60 |     private static final Pattern JSP_PAGE_ENCODING_PATTERN =
61 |             Pattern.compile("<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*[\"']([^\"']+)[\"']",
62 |                     Pattern.DOTALL);
63 | 
