95 |         Path inputPath = inputDir.toPath();
96 | 
97 |         // 1. 引数の確認
98 |         if (!inputDir.isDirectory()) {
99 |             log.error("入力ディレクトリが見つかりません: {}", inputDir);
100 |             return 1;
101 |         }
