103 |             log.error("Eclipseプロジェクトではありません (.project ファイルが見つかりません): {}", inputDir);
104 |             return 1;
105 |         }
106 |         if (outputDir.exists() && !outputDir.isDirectory()) {
107 |             log.error("出力パスはディレクトリである必要があります: {}", outputDir);
108 |             return 1;
109 |         }
110 |         if (javaTargetVersion != null && javaTargetVersion.isUnknown()) {
111 |             log.error("--javaTargetVersionが不正です: {}", javaTargetVersion);
112 |             return 1;
113 |         }
114 | 
115 |         try {
116 |             // 2. Eclipseプロジェクト情報をパース
117 |             log.info("");
118 |             log.info("[1/5] Eclipseプロジェクトを解析中...");
119 |             EclipseProject eclipseProject = EclipseProjectParser.parse(inputPath);
120 |             log.info("  プロジェクト名: {}", eclipseProject.projectName());
121 |             log.info("  種別: {}", eclipseProject.webProject() ? "Webプロジェクト (WTP)" : "Javaプロジェクト");
122 |             log.info("  Javaソースバージョン: {}", eclipseProject.javaSourceVersion());
123 |             log.info("  Javaターゲットバージョン: {}", eclipseProject.javaTargetVersion());
124 |             if (eclipseProject.webProject()) {
125 |                 log.info("  Web仕様バージョン: {}", eclipseProject.webVersion());
126 |             }
127 |             log.info("  ソースフォルダ: {}", eclipseProject.sourceFolders());
128 |             if (eclipseProject.webProject()) {
129 |                 log.info("  Webコンテンツフォルダ: {}", eclipseProject.webContentRoot());
130 |             }
131 |             log.info("  JARファイル数: {}", eclipseProject.jarFiles().size());
132 | 
133 |             if (eclipseProject.javaSourceVersion().isUnknown()) {
134 |                 log.error("Javaソースバージョンを認識できませんでした: {}", eclipseProject.javaSourceVersion());
135 |                 return 1;
136 |             }
137 | 
138 |             log.info("");
139 |             log.info("[2/5] 移行先のMavenプロジェクトを決定中...");
140 |             String defaultArtifactId = convertToArtifactId(eclipseProject.projectName());
141 |             if (groupId == null || groupId.isBlank()) {
142 |                 // オプション未指定の場合は対話的に入力を受け付ける
143 |                 try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
144 |                     log.debug("対話的入力モード開始");
145 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
146 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
147 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
148 |                     log.debug("groupId: {}", groupId);
149 |                     log.debug("artifactId: {}", artifactId);
150 |                     log.debug("version: {}", artifactVersion);
151 |                     // --convertToUtf8 指定時は sourceEncoding も対話入力
152 |                     if (convertToUtf8) {
153 |                         sourceEncoding = promptIfAbsent(reader, "sourceEncoding", sourceEncoding, null);
154 |                     }
155 |                     log.debug("sourceEncoding: {}", sourceEncoding);
156 |                 }
157 |             } else {
158 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
159 |                 if (artifactId == null || artifactId.isBlank()) {
