256 |     /**
257 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
258 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
259 |      *
260 |      * @param reader       入力ストリーム
261 |      * @param name         項目名（表示用）
262 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
263 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
264 |      * @return 確定した値
265 |      */
266 |     private static String promptIfAbsent(BufferedReader reader, String name,
267 |             String value, String defaultValue) throws Exception {
268 |         if (value != null && !value.isBlank()) {
269 |             return value;
270 |         }
271 |         while (true) {
272 |             if (defaultValue != null) {
273 |                 System.out.print(name + " [" + defaultValue + "]: ");
274 |             } else {
275 |                 System.out.print(name + ": ");
276 |             }
277 |             System.out.flush();
278 |             String line = reader.readLine();
279 |             if (line == null) {
280 |                 // EOF（パイプ等）の場合はデフォルト値を使用
281 |                 return defaultValue != null ? defaultValue : "";
282 |             }
283 |             String trimmed = line.trim();
284 |             if (trimmed.isEmpty()) {
285 |                 if (defaultValue != null) {
286 |                     return defaultValue;
287 |                 }
288 |                 // 対話的入力モードでのメッセージは，ロガーを使わず，直接System.outに出力
289 |                 System.out.print("  値を入力してください。");
290 |                 continue;
291 |             }
292 |             return trimmed;
293 |         }
294 |     }
